Here are the public test cases for feature3_timestamp_roundtrip:
{
    "description": "Round-trip an aware calendar moment through epoch-seconds conversion. The moment is converted to whole seconds since the Unix epoch and then converted back to an aware UTC instant. Sub-second precision is intentionally dropped. The output reports the intermediate epoch-seconds value and the reconstructed instant (always expressed in UTC) in ISO-8601 form together with its UTC offset in seconds. A moment supplied at a non-UTC offset round-trips to the same instant expressed in UTC.",
    "cases": [
        {
            "input": {
                "op": "timestamp_roundtrip",
                "datetime": {
                    "year": 2021,
                    "month": 6,
                    "day": 15,
                    "hour": 8,
                    "minute": 30,
                    "second": 45,
                    "tz": "UTC"
                }
            },
            "expected_output": "epoch=1623745845\niso=2021-06-15T08:30:45+00:00\nutcoffset=0\n"
        }
    ]
}

