Here are the public test cases for feature2_1_deserialize_datetime:
{
    "description": "Reconstruct a calendar moment from its portable JSON form. The decoder reads the date/time components and the timezone descriptor and rebuilds an instant whose UTC offset reflects that descriptor. When no descriptor is present the moment defaults to UTC (zero offset). A named IANA-zone descriptor yields that zone's offset for the given date. A numeric descriptor is interpreted as a fixed offset expressed in seconds and yields the corresponding fixed-offset instant. The output reports the reconstructed instant in ISO-8601 form and its UTC offset in seconds.",
    "cases": [
        {
            "input": {
                "op": "deserialize",
                "value": {
                    "__type__": "datetime",
                    "year": 2015,
                    "month": 12,
                    "day": 30,
                    "hour": 12,
                    "minute": 59,
                    "second": 22,
                    "microsecond": 333
                }
            },
            "expected_output": "type=datetime\niso=2015-12-30T12:59:22.000333+00:00\nutcoffset=0\n"
        },
        {
            "input": {
                "op": "deserialize",
                "value": {
                    "__type__": "datetime",
                    "year": 2015,
                    "month": 12,
                    "day": 30,
                    "hour": 12,
                    "minute": 59,
                    "second": 22,
                    "microsecond": 333,
                    "timezone": "Asia/Shanghai"
                }
            },
            "expected_output": "type=datetime\niso=2015-12-30T12:59:22.000333+08:00\nutcoffset=28800\n"
        }
    ]
}

Here are the public test cases for feature1_5_serialize_rrule:
{
    "description": "Serialize a recurrence-rule schedule into the portable JSON form. The result is tagged with an rrule type marker and records the frequency code, interval, and every recurrence constraint (count, until, by-weekday, by-month, etc.), defaulting unused constraints to null. Datetime anchors (the start moment and optional end moment) are stored as epoch seconds together with a companion field giving their UTC offset in minutes, so the original wall-clock offset is preserved even when two anchors denote the same instant in different zones. A by-weekday constraint is stored as a list of weekday selector objects.",
    "cases": [
        {
            "input": {
                "op": "serialize",
                "value": {
                    "kind": "rrule",
                    "freq": "MINUTELY",
                    "dtstart": {
                        "year": 2015,
                        "month": 12,
                        "day": 30,
                        "hour": 12,
                        "minute": 59,
                        "second": 22,
                        "tz": "UTC"
                    },
                    "until": {
                        "year": 2015,
                        "month": 12,
                        "day": 31,
                        "hour": 12,
                        "minute": 59,
                        "second": 22,
                        "tz": "UTC"
                    },
                    "count": 1
                }
            },
            "expected_output": "{\"__type__\": \"rrule\", \"freq\": 5, \"interval\": 1, \"wkst\": null, \"count\": 1, \"bysetpos\": null, \"bymonth\": null, \"bymonthday\": null, \"byyearday\": null, \"byeaster\": null, \"byweekno\": null, \"byweekday\": null, \"byhour\": null, \"byminute\": null, \"bysecond\": null, \"dtstart\": 1451480362, \"dtstart_tz\": 0, \"until\": 1451566762, \"until_tz\": 0}\n"
        },
        {
            "input": {
                "op": "serialize",
                "value": {
                    "kind": "rrule",
                    "freq": "WEEKLY",
                    "dtstart": {
                        "year": 2015,
                        "month": 12,
                        "day": 30,
                        "hour": 12,
                        "minute": 59,
                        "second": 22,
                        "tz": "UTC"
                    },
                    "until": {
                        "year": 2015,
                        "month": 12,
                        "day": 31,
                        "hour": 12,
                        "minute": 59,
                        "second": 22,
                        "tz": "UTC"
                    },
                    "byweekday": [
                        0,
                        2,
                        4
                    ]
                }
            },
            "expected_output": "{\"__type__\": \"rrule\", \"freq\": 2, \"interval\": 1, \"wkst\": null, \"count\": null, \"bysetpos\": null, \"bymonth\": null, \"bymonthday\": null, \"byyearday\": null, \"byeaster\": null, \"byweekno\": null, \"byweekday\": [{\"__type__\": \"weekday\", \"wkday\": 0}, {\"__type__\": \"weekday\", \"wkday\": 2}, {\"__type__\": \"weekday\", \"wkday\": 4}], \"byhour\": null, \"byminute\": null, \"bysecond\": null, \"dtstart\": 1451480362, \"dtstart_tz\": 0, \"until\": 1451566762, \"until_tz\": 0}\n"
        }
    ]
}

